import random
import string

def generate_promo(length):
    chars = string.ascii_uppercase + string.ascii_lowercase + string.digits
    return ''.join(random.choices(chars, k=length))

def generate_promo_codes(count, length=8):
    promos = []
    for _ in range(count):
        promo = generate_promo(length)
        promos.append(promo)
    print(promos)

