import tornado.ioloop
import tornado.web
from tornado.options import options

class WithdrawalFormHandler(tornado.web.RequestHandler):
    wallet = 0

    def get(self):
        self.render("withdrawal_form.html")

    def post(self):
        amount = self.get_argument("amount")

        if amount and int(amount) > 0:
            if self.wallet >= int(amount):
                self.wallet -= int(amount)
                self.render("withdrawal_success.html")
            else:
                self.render("withdrawal_failed.html", msg="Insufficient funds.")
        else:
            self.render("withdrawal_failed.html", msg="Please enter a valid amount.")

app = tornado.web.Application([
    (r"/withdraw", WithdrawalFormHandler),
],
    wallet=options.wallet,
)

if __name__ == "__main__":
    app.listen(8888)
    tornado.ioloop.IOLoop.current().start()

